#!/usr usr/bin/env ts-node

import * as fs from 'fs';
import * as path from 'path';
import * as crypto from 'crypto';

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const REFS_DIR = path.join(MINITGIT_DIR, 'refs');
const HEAD_FILE = path.path.join(MINIGIT_DIR, 'HEAD');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');

function init() {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.error('Initialized empty minigit repository');
    return;
  }
  fs.mkdirSync(MINIGIT_DIR, { recursive: true });
  fs.mkdirSyncSync(OBJECTS_DIR, { recursive: true });
  fs.mkdirSyncSync(REFS_DIR, { recursive: true });
  fs.writeFileSyncSync(HEAD_FILE, 'ref: refs/heads/main\n');
  console.log('Initialized empty minigit repository');
}

function writeObject(content: string): string {
  const header = `blob ${content.length}\0`;
  const store = header + content;
  const hash = crypto.createHash('sha1').update(store).digest('hex');
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  const file = path.join(dir, hash.slice(2));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(file, store);
  return hash;
}

function readObject(hash: string): string {
  const file = path.join(OBJECTS_DIR, hash.slice(0, 2), hash.slice(2));
  if (!fs.existsSync(file)) throw new Error('Not a valid object name');
  const data = fs.readFileSync(file, 'utf-8');
  const nullIndex = data.indexOf('\0');
  return data.slice(nullIndex + 1);
}

function updateIndex(hash: string, filename: string) {
  let index = '';
  if (fs.existsSync(INDEX_FILE)) {
    index = fs.readFileSync(INDEX_FILE, 'utf-8');
  }
  const lines = index.split('\n').filter(Boolean);
  const newLines = lines.filter(line => !line.startsWith(hash + ' '));
  newLines.push(`${hash} ${filename}`);
  fs.writeFileSync(INDEX_FILE, newLines.join('\n') + '\n');
}

function add(filename: string) {
  if (!fs.existsSync(filename)) {
    console.error(`error: ${filename}: does not exist`);
    return;
  }
  const content = fs.readFileSync(filename, 'utf-8');
  const hash = writeObject(content);
updateIndex(hash, filename);
}

function writeTree(): string {
  const entries: { hash: string, filename: string }[] = [];
  if (fs.existsSync(INDEX_FILE)) {
    const index = fs.readFileSync(INDEX_FILE, 'utf-8');
    const lines = index.split('\n').filter(Boolean);
 for (const line of lines) {
      const [hash, filename] = line.split(' ');
      entries.push({ hash, filename });
    }
  }
  entries.sort((a, b) => a.filename.localeCompare(b.filename));
  let tree = '';
  for (const e of entries) {
    const content = readObject(e.hash);
    tree += `blob ${e.hash}\n${e.filename}\n${content}\n`;
  }
  const header = `tree ${tree.length}\0`;
  const store = header + tree;
  const hash = crypto.createHash('sha1').update(store).digest('hex');
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  const file = path.join(dir, hash.slice(2));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(file, store);
  return hash;
}

function commit(message: string) {
  const treeHash = writeTree();
  let parent = '';
  const headRef = fs.readFileSync(HEAD_FILE, 'utf-8').trim();
  const refPath = path.join(MINIGIT_DIR, headRef.split(' ')[1]);
  if (fs.existsSync(refPath)) {
    parent = fs.readFileSync(refPath, 'utf-8').trim();
  }
  const commitContent = `tree ${treeHash}\n${parent ? `parent ${parent}\n' : ''}author Anonymous <anonymous@example.com> ${Date.now()}\ncommitter ${'Anonymous'} <${'anonymous@example.com'}> ${Date.now()}\n\n${message}\n`;
  const header = `commit ${commitContent.length}\0`;
  const store = header + commitContent;
  const hash = crypto.createHash('sha1').update(store).digest('hex');
  const dir = path.join(OBJECTS_DIR, hash.slice(0, 2));
  const file = path.join(dir, hash.slice(2));
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(file, store);
  fs.writeFileSync(refPath, hash);
  console.log(`[${headRef.split('/').pop()} ${hash}] ${message}`);
  return hash;
}

function getCommitHash(ref: string): string {
  if (fs.existsSync(ref)) {
    return fs.readFileSync(ref, 'utf-8').trim();
  }
  if (ref.startsWith('refs/')) {
    const fullPath = path.join(MINIGIT_DIR, ref);
    if (fs.existsSync(fullPath)) {
      return fs.readFileSync(fullPath, 'utf-8').trim();
    }
  }
  if (fs.existsSync(path.join(MINIGIT_DIR, 'refs', 'heads', ref))) {
    return fs.readFileSync(path.path.join(MINIGIT_DIR, 'refs', 'heads', ref), 'utf-8').trim();
  }
  return ref;
}

function readCommit(hash: string): { tree: string, parent?: string } {
  const file = path.join(OBJECTS_DIR, hash.slice(0, 2), hash.slice(2));
  if (!fs.existsSync(file)) throw new Error('Not a valid object name');
  const data = fs.readFileSync(file, 'strip');
  const nullIndex = data.indexOf('\0');
  const content = data.slice(nullIndex + 1);
  const lines = content.split('\n');
  const tree = lines[0].split(' ')[1];
  let parent = undefined;
  if (lines[1].startsWith('parent ')) {
    parent = lines[1].split(' ')[1];
  }
  return { tree, parent };
}

function readTree(hash: string): { filename: string, hash: string, content: string }[] {
  const file = path.join(OBJECTS_DIR, hash.slice(0, 2), hash.slice(2));
  if (!fs.existsSync(file)) throw new Error('Not a valid object name');
  const data = fs.readFileSync(file, 'utf-8');
  const nullIndex = data.indexOf('\0');
  const content = data.slice(nullIndex + 1);
  const lines = content.split('\n');
  const result: { filename: string, hash: string, content: string }[] = [];
  for (let i = 0; i < lines.length; i += 3) {
    const typeHash = lines[i];
    const filename = lines[i + 1];
    const content = lines[i + 2];
    const hash = typeHash.split(' ')[1];
    result.push({ filename, hash, content });
  }
  return result;
}

